<table><thead><tr><th colspan="4" style="text-align: center; font-size: 14pt; font-weight: bold;">PROFIT & LOSS STATEMENT</th></tr><tr><th colspan="4" style="text-align: center; font-size: 12pt; font-weight: bold;">{{ $systemName }}</th></tr><tr><th colspan="4" style="text-align: center; font-weight: bold;">{{ $data['month_label'] ?? ($data['year_label'] ?? 'Financial Report') }}</th></tr><tr><th style="background-color: #f2f2f2; border: 1px solid #000; font-weight: bold; text-align: center;">Account No</th><th style="background-color: #f2f2f2; border: 1px solid #000; font-weight: bold; text-align: center;">Description</th><th style="background-color: #f2f2f2; border: 1px solid #000; font-weight: bold; text-align: center;">Subtotal</th><th style="background-color: #f2f2f2; border: 1px solid #000; font-weight: bold; text-align: center;">Total</th></tr></thead><tbody>@php $totalRevenue = 0; @endphp @foreach($data['revenue'] as $rev) @php $totalRevenue += (float)$rev['amount']; @endphp<tr><td style="border: 1px solid #000; text-align: center;">{{ $rev['code'] }}</td><td style="border: 1px solid #000;">{{ $rev['label'] }}</td><td style="border: 1px solid #000; text-align: right;">{{ $rev['amount'] > 0 ? 'Rp' . number_format($rev['amount'], 0, ',', '.') : '-' }}</td><td style="border: 1px solid #000;"></td></tr>@endforeach<tr style="font-weight: bold;"><td colspan="2" style="border: 1px solid #000; text-align: center; background-color: #f2f2f2;">Total Revenue</td><td style="border: 1px solid #000; background-color: #f2f2f2;"></td><td style="border: 1px solid #000; text-align: right; background-color: #f2f2f2;">Rp{{ number_format($totalRevenue, 0, ',', '.') }}</td></tr><tr><td colspan="4"></td></tr>@php $totalExpense = 0; @endphp @foreach($data['expenses'] as $exp) @php $totalExpense += (float)$exp['amount']; @endphp<tr><td style="border: 1px solid #000; text-align: center;">{{ $exp['code'] }}</td><td style="border: 1px solid #000;">{{ $exp['label'] }}</td><td style="bord